    "folke/which-key.nvim",
    opts = function(_, opts)
        opts.spec = opts.spec or {}
        vim.list_extend(opts.spec, {
            { "<leader>d",  group = "debug" },
            { "<leader>f",  group = "find" },
            { "<leader>g",  group = "git" },
            { "<leader>l",  group = "lsp" },
            { "<leader>t",  group = "ui" },
            { "<leader>w",  group = "window" },
            { "]",          group = "next" },
            { "[",          group = "prev" },
        })
    end,
},

